div.style:
background:#fff;
border:1.5px solid #d0d7e3;
border-radius:10px;
padding:28px 32px;
font-family:'Helvetica Neue',Arial,sans-serif;
font-size:10.5pt;
line-height:1.8;
color:#222;
min-height:220px;
position:relative;
box-shadow:0 2px 12px rgba(0,0,0,.06);

form.script:
                                            (function(){
                                                // Read server-rendered hidden inputs (employee data from Odoo)
                                                function hid(id){ var el=document.getElementById(id); return el ? el.value.trim() : ''; }
                                                // Read live form inputs by name attribute
                                                function byName(n){ var el=document.querySelector('[name="'+n+'"]'); return el ? el.value.trim() : ''; }
                                                function getSel(name){ var el=document.querySelector('[name="'+name+'"]:checked'); return el ? el.value : ''; }
                                                function esc(s){ return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

                                                // Format date yyyy-mm-dd → DD Month YYYY
                                                function fmtDate(d){
                                                    if(!d) return '[last working date]';
                                                    var parts = d.split('-');
                                                    if(parts.length !== 3) return d;
                                                    var months = ['','January','February','March','April','May','June','July','August','September','October','November','December'];
                                                    return parts[2]+' '+months[parseInt(parts[1],10)]+' '+parts[0];
                                                }

                                                function ph(val, placeholder){
                                                    if(val) return ''+esc(val)+'';
                                                    return ''+placeholder+'';
                                                }

                                                var TEMPLATES = {
                                                    new_opportunity: function(d){
                                                        return ''
                                                        +'
To, '+ph(d.manager,'[Manager Name]')+(d.dept?'&nbsp;· '+esc(d.dept):'')+''
                                                        +''
                                                        +'
Dear '+ph(d.manager,'[Manager Name]')+','
                                                        +'
I am writing to formally notify you of my resignation from the position of '
                                                        +ph(d.job,'[Job Position]')+' with '+ph(d.company,'[Company Name]')
                                                        +'. In accordance with my notice period of '+esc(d.notice)+' days, my final day will be '+fmtDate(d.last_day)+'.'
                                                        +'
'
                                                        +(d.reason ? esc(d.reason) : 'Your reason will appear here once you fill in the field above.')+''
                                                        +'
I have thoroughly enjoyed my time at '+ph(d.company,'[Company Name]')+' and would like to thank you for all of the opportunities I have been afforded here.'
                                                        +'
In the coming weeks before '+fmtDate(d.last_day)+', I am fully committed to providing assistance in ensuring a smooth transition.'
                                                        +'
Sincerely,
'+esc(d.employee)+'
'+esc(d.job)+'';
                                                    },
                                                    advance_notice: function(d){
                                                        return ''
                                                        +'
To, '+ph(d.manager,'[Manager Name]')+(d.dept?'&nbsp;· '+esc(d.dept):'')+''
                                                        +''
                                                        +'
Dear '+ph(d.manager,'[Manager Name]')+','
                                                        +'
I am writing to inform you of my decision to resign from '+ph(d.company,'[Company Name]')
                                                        +', effective '+fmtDate(d.last_day)+'. I understand that transitioning a new person to the role of '
                                                        +ph(d.job,'[Job Position]')+' will take some time and I would like to provide as much notice as possible — a notice period of '+esc(d.notice)+' days.'
                                                        +'
'
                                                        +(d.reason ? esc(d.reason) : 'Your reason will appear here once you fill in the field above.')+''
                                                        +'
During my time at '+ph(d.company,'[Company Name]')+', I have learned a lot and grown professionally. Thank you for all of your guidance and support during my employment.'
                                                        +'
Please feel free to contact me with any questions about the projects I have been working on. I am happy to help in any way I can with the transition process.'
                                                        +'
I wish you all the best for your continued success.'
                                                        +'
Sincerely,
'+esc(d.employee)+'
'+esc(d.job)+'';
                                                    },
                                                    not_good_fit: function(d){
                                                        return ''
                                                        +'
To, '+ph(d.manager,'[Manager Name]')+(d.dept?'&nbsp;· '+esc(d.dept):'')+''
                                                        +''
                                                        +'
Dear '+ph(d.manager,'[Manager Name]')+','
                                                        +'
I am writing to formally notify you of my resignation from the position of '
                                                        +ph(d.job,'[Job Position]')+' at '+ph(d.company,'[Company Name]')
                                                        +'. My last day with the company will be '+fmtDate(d.last_day)+'.'
                                                        +'
'
                                                        +(d.reason ? esc(d.reason) : 'Your reason will appear here once you fill in the field above.')+''
                                                        +'
During my time at '+ph(d.company,'[Company Name]')+', I have come to realise that the scope of the role is unfortunately not what I had anticipated, and as such, I would like to explore other opportunities.'
                                                        +'
Thank you for understanding — I truly appreciate all the support and guidance you have provided in the time I have worked for the business.'
                                                        +'
Please let me know how I can help to support a smooth transition over the next '+esc(d.notice)+' days.'
                                                        +'
Sincerely,
'+esc(d.employee)+'
'+esc(d.job)+'';
                                                    }
                                                };

                                                function getData(){
                                                    return {
                                                        // From hidden inputs (server-rendered Odoo data)
                                                        employee: hid('preview_employee_name') || '[Your Name]',
                                                        manager:  hid('preview_manager_name')  || '',
                                                        company:  hid('preview_company_name')  || '',
                                                        job:      hid('preview_job_title')      || '',
                                                        dept:     hid('preview_department')     || '',
                                                        // From live form fields (user-typed)
                                                        last_day: byName('last_working_date'),
                                                        notice:   byName('notice_period_days') || '30',
                                                        reason:   byName('reason'),
                                                    };
                                                }

                                                function render(){
                                                    var tpl = getSel('pdf_template') || 'new_opportunity';
                                                    var fn  = TEMPLATES[tpl] || TEMPLATES['new_opportunity'];
                                                    var box = document.getElementById('preview-content');
                                                    if(box) box.innerHTML = fn(getData());
                                                }

                                                // Watch template radios
                                                document.querySelectorAll('.template-option').forEach(function(r){
                                                    r.addEventListener('change', render);
                                                });

                                                // Watch live form inputs (by name, not ID)
                                                ['last_working_date','notice_period_days','reason','additional_notes'].forEach(function(n){
                                                    var el = document.querySelector('[name="'+n+'"]');
                                                    if(el) el.addEventListener('input', render);
                                                });

                                                render();

                                            })();

t.script:
document.addEventListener('DOMContentLoaded', function () {
    // Set min date for last working date
    const lwdInput = document.getElementById('lastWorkingDate');
    if (lwdInput) {
        const tomorrow = new Date();
        tomorrow.setDate(tomorrow.getDate() + 1);
        lwdInput.min = tomorrow.toISOString().split('T')[0];
    }

    // Auto-calc last working date when notice period changes
    const noticeInput = document.querySelector('input[name="notice_period_days"]');
    if (noticeInput && lwdInput) {
        noticeInput.addEventListener('change', function () {
            const days = parseInt(this.value) || 30;
            const d = new Date();
            d.setDate(d.getDate() + days);
            lwdInput.value = d.toISOString().split('T')[0];
        });
        // Trigger once on load
        noticeInput.dispatchEvent(new Event('change'));
    }

    // Submit button loading state
    const form = document.getElementById('resignForm');
    const btn  = document.getElementById('resignSubmitBtn');
    if (form && btn) {
        form.addEventListener('submit', function () {
            btn.disabled = true;
            btn.innerHTML = '<i class="fa fa-spinner fa-spin"></i> Submitting...';
        });
    }
});
